mapper.select:

where a.del_flag = '0'

    AND a.area_id = #{areaId}


    AND a.parent_id = #{parentId}


    AND a.area_name like concat('%', #{areaName}, '%')


    AND a.area_code like concat('%', #{areaCode}, '%')


    AND a.status = #{status}

order by a.parent_id, a.order_num

mapper.update:
update garden_area
parent_id = #{parentId}, ancestors = #{ancestors}, area_name = #{areaName}, area_code = #{areaCode}, order_num = #{orderNum}, status = #{status}, remark = #{remark}, update_by = #{updateBy}, update_time = sysdate()
where area_id = #{areaId}

update garden_area set ancestors =

    when #{item.areaId} then #{item.ancestors}

where area_id in

    #{item.areaId}
